function close$VoucherBookTemplatesCreate$(f) {try {f.remove_onResponseComplete(on$Filter$VoucherBookTemplatesCreate$ResponseComplete);} catch (ex) {}}
function on$Filter$VoucherBookTemplatesCreate$ResponseComplete(sender, e) {
  var f = e.object, g = f.grid, context = e.type.Context, result = e.type.Result;
